import React, { useEffect, useState } from "react";
import { LineChart, Line, XAxis, YAxis, Tooltip, CartesianGrid } from "recharts";

const BusTrendChart = () => {
  const [trendData, setTrendData] = useState([]);

  useEffect(() => {
    const fetchTrend = async () => {
      try {
        const response = await fetch("http://localhost:8000/buses");
        const buses = await response.json();
        const activeCount = buses.filter(b => b.status === "active").length;
        const ghostCount = buses.filter(b => b.status === "ghost").length;

        setTrendData(prev => [
          ...prev.slice(-9),
          { time: new Date().toLocaleTimeString(), active: activeCount, ghost: ghostCount }
        ]);
      } catch (error) {
        console.error("Error fetching bus data for chart:", error);
      }
    };

    fetchTrend();
    const interval = setInterval(fetchTrend, 5000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div style={{ width: "90%", margin: "20px auto" }}>
      <LineChart width={800} height={250} data={trendData}>
        <XAxis dataKey="time" />
        <YAxis />
        <Tooltip />
        <CartesianGrid stroke="#f5f5f5" />
        <Line type="monotone" dataKey="active" stroke="green" />
        <Line type="monotone" dataKey="ghost" stroke="red" />
      </LineChart>
    </div>
  );
};

export default BusTrendChart;
